  var view = document.getElementById("view");
  var div = document.createElement("div");
  div.classList = "outer-container";
  view.appendChild(div);
  var subDiv = document.createElement("div");
  subDiv.classList = "inner-container";
  div.appendChild(subDiv);
  var ui = document.createElement("div");
  ui.id = "ui";
  subDiv.appendChild(ui);
  var sheet = document.createElement("style");
  sheet.innerHTML = `



.outer-container {
  font-family: ArialRoundedMTBold;
  font-size: 2rem;
  color: rgba(241, 231, 231, 0.808);
  background-color: rgb(31, 33, 46);

  position: absolute;
  translate: translation(-50%, -50%);
  left: 0.0px;
  top: 0.0px;

  display: table;

  width: 100%;
  height: 100%;
  margin: 0;
  padding: 0;

  pointer-events: none; 
  background-color: transparent;

}

#ui {
  background-color: black;
  pointer-events: none;
}

.inner-container {
  display: table-cell;
  vertical-align: middle;
  text-align: center;
  margin: 0;
  padding: 0;
}

.box {
  display: inline-block;
  margin: 5px;
  padding: 0px;
  border-radius: 8px;
  pointer-events: auto;
  background-color: transparent;
}

.img-center {

  width: 5rem;
  height: 5rem;



  border-radius: 3rem; 
  border-style: solid;
  border-color: rgba(241, 231, 231, 0.808);
  padding: 0.3rem;
  
}
`;
